import{_ as a,o as b,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"宝可梦技能—妖精","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—妖精.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—妖精.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—妖精.md"};function d(o,e,_,l,i,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"宝可梦技能—妖精",tabindex:"-1"},[p("宝可梦技能—妖精 "),r("a",{class:"header-anchor",href:"#宝可梦技能—妖精","aria-label":'Permalink to "宝可梦技能—妖精"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调019")])])],-1),n('<h1 id="宝可梦技能—妖精-1" tabindex="-1">宝可梦技能—妖精 <a class="header-anchor" href="#宝可梦技能—妖精-1" aria-label="Permalink to &quot;宝可梦技能—妖精&quot;">​</a></h1><p>宝可梦技能—妖精</p><p>特别说明：妖精系技能中物理系技能造成的伤害均为物理伤害。法伤技能造成的均为纯能量伤害。<br> 所有妖精系技能皆具有【法破】特性，不在每项技能中赘述。</p><p>天使之吻 D+500<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：妖精系变化技能，该宝可梦进行对一个目标一次施法检定抛出一个飞吻，对方以意志豁免，射程25米。这次攻击不造成伤害，若对方豁免失败，则目标无法区分敌我随机攻击目标，持续失败差额值轮，该效果为C级幻象来源的混乱效果。<br> 差价升级：C+1000<br> 差价升级后仍可使用技艺的较低级别版本。<br> 则本技能射程提升至75米，造成效果的来源提升至B级幻象来源。</p><p>撒娇 C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：妖精系变化技能，该宝可梦进行对一个目标一次施法检定，对方以意志豁免，射程55米。这次攻击不造成伤害，若对方豁免失败，则目标降低等同于失败数的攻击检定DP，上限为宝可梦的风度属性，持续一个场景。</p><p>月光 B+2000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：妖精系变化技能，该宝可梦对于月光精华进行吸收，若此时为白天，则该宝可梦一轮内获得等同于自身耐力属性点一半的快速医疗点数（与夜晚共用医疗点）。若此时为夜晚，则该宝可梦一轮内获得等同于自身耐力属性点1.5倍的快速医疗点数（医疗点：288）。</p><p>吸取之吻 C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：妖精系法伤技能，该宝可梦进行一次施法攻击检定，射程30米。这次攻击附带1点来自于技艺的附加成功并具有【破魔5】【吸血5】。<br> 差价升级至B+2000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：攻击附带的吸血点数提升至10，破魔提升至7，并具有【接触攻击】特性。</p><p>嬉闹 C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：妖精系物理技能，该宝可梦进行一次近战攻击检定造成钝击伤害，这次攻击附带6dp技艺加值和1点来自于技艺的附加成功并具有【高速10】【破甲10】。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：攻击附带技艺加值提升至该宝可梦的力量属性点，命中后降低敌人9点攻击检定，持续一个场景（不可叠加），高速提升至15点。<br> A级效果：在先前的基础上，本次攻击忽略对手的格挡和洞察防御，这是一个A级祝福来源的效果（视为宝可梦本次攻击获得了远古妖精的祝福），并具有【8加骰】特性。</p><p>妖精之风 D+500<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：妖精系法伤技能，该宝可梦进行一次施法攻击检定，射程15米。这次攻击具有等同于施法主属性点一半的妖精能量加值。<br> 差价升级至C+1000<br> 差价升级后仍可使用技艺的较低级别版本。<br> C级效果：攻击具有的妖精能量加值提升为等于施法主属性点，射程提升至40米。</p><p>月亮之力 C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：妖精系法伤技能，该宝可梦进行一次施法攻击检定，这次攻击检定+9dp的妖精能量加值，射程30米。这次攻击额外具有10破魔和5高速的特性。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：这次攻击射程提升至90米，获得【能量武器】【8加骰】【湮灭】特性。攻击命中后降低敌人9点施法检定，持续一个场景（不可叠加）。<br> A级效果：这次攻击攻击检定附带的妖精能量加值提升为该宝可梦的施法属性值，射程提升至敏感范围，本次攻击忽略对手的盔甲、天生防御，这是一个A级的诅咒来源效果（视为宝可梦本次施法是将月亮之力直接灌注至目标体内）。</p><p>魔法闪耀 C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：妖精系法伤技能，该宝可梦进行一次施法攻击检定，这次攻击检定+9dp的妖精能量加值，射程30米。这次攻击额外具有10破甲和5破魔的特性。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：这次攻击附带的妖精能量加值提升至宝可梦施法属性主属性点并获得1点来自于技艺的附加成功，射程提升至90米，并具有【能量武器】特性。<br> A级效果：这次攻击射程提升至敏感范围，具有能量武器特性，破甲、破魔提升至15。这次攻击忽略对手的洞察、格挡防御，这是一个A级的幻象来源效果（魔法强光照射，令敌人应接不暇！）。</p><p>圆瞳 D+500<br> 指挥动作：移动动作<br> 宝可梦消耗动作：移动动作<br> 效果：妖精系变化技能，使用该技能前必须在战斗轮开始前进行声明，若如此做则立刻提升该宝可梦6点先攻，仅本轮生效。到该宝可梦回合时进行一次施法检定，射程15米，意志豁免。若成功则目标降低等于胜出数的攻击检定，上限为5，该效果持续到目标本轮行动结束。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const A=a(s,[["render",d]]);export{f as __pageData,A as default};
